function normalizeInput(text, script) {
  if (script === "malayalam") {
    return text
      .replace(/ൺ/g, "ണ്")
      .replace(/ൻ/g, "ന്")
      .replace(/ർ/g, "ര്")
      .replace(/ൽ/g, "ല്")
      .replace(/ൾ/g, "ള്");
  }
  return text;
}

function postProcess(text, targetScript) {
  if (targetScript === "tamil") {
    return text
      .replace(/க்ஹ/g, "க")
      .replace(/ஜ்ஹ/g, "ஜ")
      .replace(/த்ஹ/g, "த")
      .replace(/ப்ஹ/g, "ப");
  }

  if (targetScript === "malayalam") {
    return text
      .replace(/ന്(?=\s|$)/g, "ൻ")
      .replace(/ല്(?=\s|$)/g, "ൽ")
      .replace(/ള്(?=\s|$)/g, "ൾ")
      .replace(/ര്(?=\s|$)/g, "ർ");
  }

  return text;
}

module.exports = { normalizeInput, postProcess };